#!/usr/bin/env node
const { execSync, spawnSync } = require('child_process')
const fs = require('fs')
const path = require('path')

try {
  process.env = require('../../../env.json')
} catch {
  process.env = { PORT: '8080' }
}
const {
  BITCOIN_DATADIR,
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT
} = process.env

const sleep = (ms) => new Promise(r => setTimeout(r, ms))
const run = (cmd, opts = {}) => {
  try {
    return execSync(cmd, { stdio: 'pipe', encoding: 'utf8', ...opts }).trim()
  } catch (e) {
    if (!opts.ignoreError) throw e
    return e.stderr?.toString() || e.message || ''
  }
}

module.exports = {
  async start () {
    console.log('=== Starting Bitcoin Regtest ===')
    if (!fs.existsSync(BITCOIN_DATADIR)) {
      console.log(`Creating Bitcoin data dir: ${BITCOIN_DATADIR}`)
      fs.mkdirSync(BITCOIN_DATADIR, { recursive: true })
    }

    const ps = spawnSync('pgrep', ['-x', 'bitcoind'])
    if (ps.status === 0) {
      console.log('bitcoind already running — skipping.')
    } else {
      run(
        `bitcoind -regtest -daemon \
        -datadir="${BITCOIN_DATADIR}" \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcallowip=127.0.0.1 \
        -rpcport=${BITCOIN_RPCPORT} \
        -fallbackfee=0.0002`
      )
    }

    // wait until ready
    while (true) {
      const res = spawnSync('bitcoin-cli', [
        '-regtest',
        `-rpcuser=${BITCOIN_RPCUSER}`,
        `-rpcpassword=${BITCOIN_RPCPASSWORD}`,
        `-rpcport=${BITCOIN_RPCPORT}`,
        'getblockchaininfo'
      ])
      if (res.status === 0) break
      await sleep(500)
    }
    console.log('✅ bitcoind ready.')
  },

  async stop () {
    console.log('Stopping bitcoind...')
    try {
      run(
        `bitcoin-cli -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport="${BITCOIN_RPCPORT}" stop`,
        { ignoreError: true }
      )
      console.log('bitcoind stop requested.')
    } catch {
      console.log('bitcoind may not be running.')
    }
  }
}
